import React from 'react';
import edgar from '../images/edgar.jpg';
import Greeting from './Greeting';


class HeaderContent extends React.Component{
    render(){
        return(
            <div className="headerContent">
                <div class="col-sm-2 proImgWrapper">
                    <div class="col-sm-6"></div>
                    <div class="col-sm-6">
                        <img class="proImg animated bounceInRight delay-5s" src={edgar} width="75px" alt="Edgar face"/>
                    </div>				
                </div>
			<div class="col-sm-6 headerCt">				
				<div>
					<Greeting />

					<div class="greeting"> 	
						<br /> I'm super excited to meet you.
					</div>
					<div class="intro"><span class="typing"></span></div> 
					<div class="job">a passionate UI/UX Developer.</div> <br />
					<div class="boast">Want an awesome website?</div>
					<div class="boast">You are in the right place</div>
				</div>
				<div class="btnWrapper">
					<a href="#projects"> <button class="btn btnProject">See Projects</button></a>
					<a href="#tech"> <button class="btn btnTech">See Tech Stack</button></a>
				</div>
			</div>
			<div class="col-sm-2"></div>
            </div>
        )
    }
}

export default HeaderContent;