import React from 'react';
import Typing from 'react-typing-animation';

class Greeting extends React.Component{
    render(){
        return(
            <div className='Greeting'>
                <Typing speed={200}>
                    <span>Hi there,</span>
                    <div>I am Edgar Tinkamanyire,</div>
                </Typing>
            </div>
        )
    }
}

export default Greeting;